const { execSync } = require('child_process');

// 1. Get the previous output (Target Creation Result)
const prevOutput = items[0].json.stdout;

// 2. Extract the Target ID using Regex
const match = prevOutput.match(/id="([^"]+)"/);
const targetId = match ? match[1] : null;

if (!targetId) {
  throw new Error("Could not find Target ID in previous output");
}

// 3. Get the IP Name from the earlier 'Code' node
const ipObjetivo = $('Code').first().json.ip_objetivo;

// 4. Construct Command
const xml = `<create_task><name>Scan ${ipObjetivo}</name><config id='daba56c8-73ec-11df-a475-002264764cea'/><target id='${targetId}'/><scanner id='08b69003-5fc2-4037-a479-93b440211c73'/></create_task>`;
const cmd = `/home/node/gvm-env/bin/python3 -m gvmtools.cli --gmp-username admin --gmp-password admin123 socket --socketpath /run/gvmd/gvmd.sock --xml "${xml}"`;

try {
  const stdout = execSync(cmd).toString();
  return [{ json: { stdout } }];
} catch (error) {
  throw new Error(error.message);
}

const { execSync } = require('child_process');

// 1. Get data from previous node
const hosts = items[0].json.all_ips;
const count = items[0].json.cantidad_hosts;
const now = new Date().toISOString();

// 2. Construct Command
const xml = `<create_target><name>Target Masivo (${count} hosts) - ${now}</name><hosts>${hosts}</hosts><port_list id='33d0cd82-57c6-11e1-8ed1-406186ea4fc5'/></create_target>`;
const cmd = `/home/node/gvm-env/bin/python3 -m gvmtools.cli --gmp-username admin --gmp-password admin123 socket --socketpath /run/gvmd/gvmd.sock --xml "${xml}"`;

try {
  const stdout = execSync(cmd).toString();
  return [{ json: { stdout } }];
} catch (error) {
  throw new Error(error.message);
}

// 1. Capturamos la salida de Nmap
const nmapData = items[0].json.nmaprun;

// 2. CONFIGURACIÓN: Lista Negra (IPs que NO queremos escanear)
const ipsIgnoradas = ["192.168.122.1", "192.168.122.2", "192.168.122.79"];

// --- VERIFICACIÓN INICIAL ---
if (!nmapData || !nmapData.host) {
  return [{
    json: { all_ips: "", ip_objetivo: "", cantidad_hosts: 0, encontrados: false, error: "Nmap no devolvió datos" }
  }];
}

// 3. Normalizamos los hosts
let hostsArray = nmapData.host;
if (!Array.isArray(hostsArray)) {
  hostsArray = [hostsArray];
}

const ipsValidas = [];

// 4. Procesamos y filtramos
for (const host of hostsArray) {
  // Solo si la máquina responde ('up')
  if (host.status && host.status.state === 'up') {
    let ip = "";
    if (Array.isArray(host.address)) {
      const ipv4 = host.address.find(addr => addr.addrtype === 'ipv4');
      ip = ipv4 ? ipv4.addr : host.address[0].addr;
    } else {
      ip = host.address.addr;
    }

    // 🔥 FILTRO DE EXCLUSIÓN 🔥
    if (ip && !ipsIgnoradas.includes(ip)) {
      ipsValidas.push(ip);
    }
  }
}

// 5. RESPUESTA FINAL
if (ipsValidas.length === 0) {
  return [{
    json: {
      all_ips: "",
      ip_objetivo: "",
      cantidad_hosts: 0,
      encontrados: false,
      mensaje: "No se encontraron hosts nuevos (todos fueron ignorados o no responden)."
    }
  }];
}

const listaFinal = ipsValidas.join(", ");

return [{
  json: {
    all_ips: listaFinal,        
    ip_objetivo: listaFinal,    
    cantidad_hosts: ipsValidas.length,
    encontrados: true
  }
}];

