const { execSync } = require('child_process');

// 1. Get the previous output (Start Task Result)
// This output contains the <report_id> we need to download the results.
const prevOutput = items[0].json.stdout;

// 2. Extract Report ID using Regex
const match = prevOutput.match(/<report_id>([^<]+)<\/report_id>/);
const reportId = match ? match[1] : null;

if (!reportId) {
  throw new Error("Could not find Report ID in StartTask output");
}

// 3. Construct Command to get full report
const xml = `<get_reports report_id='${reportId}' format_id='a994b278-1f62-11e1-96ac-406186ea4fc5' details='1'/>`;
const cmd = `/home/node/gvm-env/bin/gvm-cli --gmp-username admin --gmp-password admin123 socket --socketpath /run/gvmd/gvmd.sock --xml "${xml}"`;

try {
  const stdout = execSync(cmd).toString();
  return [{ json: { stdout } }];
} catch (error) {
  throw new Error(error.message);
}

// 1. Obtenemos todos los resultados crudos
const vulns = items.map(item => item.json);

if (!vulns.length) {
  return [{ json: { email_body: "Sin resultados", subject: "Scan vacío" } }];
}

// --- HELPERS ---
const toText = (val) => {
    if (!val) return "N/A";
    if (typeof val === 'string') return val;
    if (typeof val === 'object' && val._) return val._; 
    return JSON.stringify(val);
};

// Función para sacar la IP limpia de cada item
const getIP = (v) => {
    if (v.host && v.host._) return v.host._;
    if (typeof v.host === 'string') return v.host;
    return "Desconocido";
};

// 2. Lógica Multi-Host
// Sacamos la lista de IPs únicas que hay en el escaneo (ej: 192.168.100.10, 192.168.100.20)
const uniqueHosts = [...new Set(vulns.map(v => getIP(v)))];
const hostsString = uniqueHosts.join(', ');

const scanDate = vulns[0].timestamp || new Date().toISOString();

// 3. Estadísticas Globales (Sumamos todo lo que encontramos en la red)
const critical = vulns.filter(v => v.severity >= 9.0);
const high = vulns.filter(v => v.severity >= 7.0 && v.severity < 9.0);
const medium = vulns.filter(v => v.severity >= 4.0 && v.severity < 7.0);
const low = vulns.filter(v => v.severity < 4.0);

// 4. Armado del HTML Multi-Host
const htmlReport = `
<div style="font-family: sans-serif; color: #222;">
  <h2 style="border-bottom: 2px solid #444;">🛡️ Reporte de Red Unificado</h2>
  <div style="background-color: #f8f9fa; padding: 10px; border-radius: 5px; margin-bottom: 20px;">
    <p style="margin: 0;">
      <strong>Hosts Escaneados:</strong> ${hostsString}<br>
      <strong>Fecha:</strong> ${scanDate}<br>
      <strong>Total Hallazgos:</strong> ${vulns.length}
    </p>
  </div>

  <table style="width: 100%; border-collapse: collapse; margin-bottom: 20px;">
    <tr style="background: #333; color: white;">
       <th style="padding: 8px;">Crítica</th>
       <th style="padding: 8px;">Alta</th>
       <th style="padding: 8px;">Media</th>
       <th style="padding: 8px;">Baja</th>
    </tr>
    <tr style="text-align: center; font-size: 1.2em;">
       <td style="border: 1px solid #ccc; color: red; font-weight: bold; padding: 10px;">${critical.length}</td>
       <td style="border: 1px solid #ccc; color: orange; font-weight: bold; padding: 10px;">${high.length}</td>
       <td style="border: 1px solid #ccc; color: #d4a017; padding: 10px;">${medium.length}</td>
       <td style="border: 1px solid #ccc; color: green; padding: 10px;">${low.length}</td>
    </tr>
  </table>

  <h3>🚨 Hallazgos Críticos y Altos</h3>
  ${[...critical, ...high].length === 0 ? '<p>No hay vulnerabilidades críticas o altas en la red.</p>' : ''}

  ${[...critical, ...high].map(v => `
    <div style="border: 1px solid #ddd; padding: 15px; margin-bottom: 15px; border-left: 5px solid ${v.severity >= 9 ? 'red' : 'orange'}; background-color: #fff;">

      <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 10px;">
         <h3 style="margin: 0; color: #333;">${toText(v.name)}</h3>
         <span style="background-color: #333; color: #fff; padding: 3px 8px; border-radius: 3px; font-size: 0.8em;">
            🖥️ ${getIP(v)}
         </span>
      </div>

      <div style="font-size: 0.9em; color: #555; margin-bottom: 10px;">
        <strong>Severidad:</strong> ${v.severity} | 
        <strong>Puerto:</strong> ${toText(v.port)} | 
        <strong>CVE:</strong> ${toText(v.cve)}
      </div>

      <p style="margin: 0 0 10px 0;"><strong>Descripción:</strong><br> ${toText(v.description).substring(0, 300)}...</p>

      <div style="background: #f1f1f1; padding: 8px; border-radius: 4px; font-size: 0.9em;">
        <strong>💡 Solución:</strong> ${toText(v.solution).substring(0, 250)}...
      </div>
    </div>
  `).join('')}

  <hr>
  <small>Reporte automático N8N - Hosts: ${uniqueHosts.length}</small>
</div>
`;

return [{
  json: {
    email_body: htmlReport,
    subject: `Reporte de Red (${uniqueHosts.length} Hosts) - ${critical.length > 0 ? '🔴 CRITICO' : '🔵 INFO'}`
  }
}];

// Este código asume que el nodo anterior se llama "XML Parse"
// Ajusta el nombre si le pusiste otro.

const reportData = items[0].json;

// Navegamos la estructura de OpenVAS para encontrar los resultados
// A veces es report.report.results.result, a veces varía un poco según la versión.
// El 'try-catch' es por seguridad.

let rawResults = [];
try {
  // Ajuste según la estructura simplificada del nodo XML de n8n
  rawResults = reportData.get_reports_response.report.report.results.result;
} catch (error) {
  // Si no hay resultados o falló la ruta
  return [];
}

// Si rawResults no es un array (es un solo resultado), lo convertimos
if (!Array.isArray(rawResults)) {
  rawResults = [rawResults];
}

const cleanVulnerabilities = rawResults.map(vuln => {
  return {
    json: {
      scan_id: reportData.get_reports_response.report.id,
      timestamp: reportData.get_reports_response.report.creation_time,
      host: vuln.host['#text'] || vuln.host, // A veces viene como objeto
      port: vuln.port,
      // La severidad viene como string "10.0", la pasamos a numero
      severity: parseFloat(vuln.severity),
      name: vuln.name,
      description: vuln.description,
      // Intentamos sacar el CVE y la Solución si existen
      cve: vuln.nvt?.cve || 'N/A',
      solution: vuln.nvt?.solution || 'No solution provided',
      solution_type: vuln.nvt?.solution_type || 'Unspecified'
    }
  };
});

// FILTRO OPCIONAL: Sacar logs informativos (Severity 0.0)
// Descomenta la linea de abajo si solo queres cosas peligrosas
// return cleanVulnerabilities.filter(item => item.json.severity > 0.0);

return cleanVulnerabilities;
